export {};
hopp.test("`hopp.response.body.asJSON()` parses response body as JSON", () => {
    const responseJSON = hopp.response.body.asJSON()
    const data = JSON.parse(responseJSON.data)
    hopp.expect(data.name).toBe('John Doe');
    hopp.expect(data.age).toBeType("number")
})

hopp.test("`hopp.response.body.asText()` parses response body as plain text", () => {
    const textResponse = hopp.response.body.asText()
    hopp.expect(textResponse).toInclude('\"test-header\":\"test\"')
})

hopp.test("hopp.response.body.bytes()` parses response body as raw bytes", () => {
    const rawResponse = hopp.response.body.bytes()
    hopp.expect(rawResponse[0]).toBe(123)
})

